'use strict';
const express = require('express');
const router = express.Router();
const Multer = require('multer');
const { authRole } = require('../helpers/auth');
const userController = require('../controllers/user.controller');

const ALL_ROLES = ['admin', 'sourcing_manager', 'sales', 'designer', 'production', 'vendor'];
const photoUpload = Multer({
  storage: Multer.memoryStorage(),
  limits: { fileSize: 5 * 1024 * 1024 }, // 5 MB max
  fileFilter: (_req, file, cb) => {
    if (!file.mimetype.startsWith('image/')) {
      return cb(new Error('Only image files are allowed'));
    }
    cb(null, true);
  },
});

// GET /api/user/me — current user's profile
router.get('/me', authRole(ALL_ROLES), userController.getProfile);

// POST /api/user/photo — upload/replace profile photo
router.post('/photo', authRole(ALL_ROLES), photoUpload.single('photo'), userController.uploadProfilePhoto);

module.exports = router;

