'use strict';
const sql = require('../models/db');

const UserService = {};

/**
 * Return { firstName, name, email, photoUrl } for a user by id.
 * Returns null if the user is not found.
 */
UserService.getProfile = async (userId) => {
  const user = await sql.users.findOne({
    where: { id: userId },
    attributes: ['id', 'name', 'lastname', 'email', 'profile_photo'],
  });
  if (!user) return null;
  return {
    firstName: user.name || '',
    name: `${user.name || ''} ${user.lastname || ''}`.trim(),
    email: user.email || '',
    photoUrl: user.profile_photo || null,
  };
};

/**
 * Persist a new photo URL for a user. Returns the URL.
 */
UserService.updateProfilePhoto = async (userId, photoUrl) => {
  await sql.users.update(
    { profile_photo: photoUrl },
    { where: { id: userId } }
  );
  return photoUrl;
};

module.exports = UserService;

