'use strict';

// ── Mocks ────────────────────────────────────────────────────────────────────

jest.mock('../../models/db', () => ({
  users: {
    findOne: jest.fn(),
    update: jest.fn(),
  },
}));

jest.mock('../../helpers/auth', () => ({
  getUserInfo: jest.fn(),
}));

const mockPutObject = jest.fn().mockResolvedValue({});
jest.mock('@aws-sdk/client-s3', () => ({
  S3: jest.fn().mockImplementation(() => ({ putObject: mockPutObject })),
}));

jest.mock('../../config/digitalocean.config', () => ({
  ACCESS_KEY: 'key',
  SECRET_KEY: 'secret',
  ENDPOINT_URL: 'https://nyc3.digitaloceanspaces.com',
  BUCKET_NAME: 'test-bucket',
  PUBLIC_URL: 'https://test-bucket.nyc3.digitaloceanspaces.com',
}));

// ── Imports (after mocks) ─────────────────────────────────────────────────────

const sql = require('../../models/db');
const { getUserInfo } = require('../../helpers/auth');
const UserService = require('../../services/user.service');
const { getProfile, uploadProfilePhoto } = require('../../controllers/user.controller');

// ── Helpers ───────────────────────────────────────────────────────────────────

function makeRes() {
  const res = {};
  res.status = jest.fn().mockReturnValue(res);
  res.json = jest.fn().mockReturnValue(res);
  return res;
}

// ═════════════════════════════════════════════════════════════════════════════
// UserService
// ═════════════════════════════════════════════════════════════════════════════

describe('UserService.getProfile', () => {
  afterEach(() => jest.clearAllMocks());

  test('returns formatted profile when user exists', async () => {
    sql.users.findOne.mockResolvedValue({
      id: 1, name: 'Albert', lastname: 'Hazan',
      email: 'albert@example.com', profile_photo: 'https://cdn.example.com/photo.jpg',
    });
    const result = await UserService.getProfile(1);
    expect(result).toEqual({
      firstName: 'Albert',
      name: 'Albert Hazan',
      email: 'albert@example.com',
      photoUrl: 'https://cdn.example.com/photo.jpg',
    });
  });

  test('returns null when user not found', async () => {
    sql.users.findOne.mockResolvedValue(null);
    const result = await UserService.getProfile(99);
    expect(result).toBeNull();
  });

  test('photoUrl is null when profile_photo is empty', async () => {
    sql.users.findOne.mockResolvedValue({
      id: 2, name: 'Jane', lastname: 'Doe', email: 'jane@example.com', profile_photo: null,
    });
    const result = await UserService.getProfile(2);
    expect(result.photoUrl).toBeNull();
  });

  test('name is trimmed when lastname is missing', async () => {
    sql.users.findOne.mockResolvedValue({
      id: 3, name: 'Solo', lastname: null, email: 'solo@example.com', profile_photo: null,
    });
    const result = await UserService.getProfile(3);
    expect(result.name).toBe('Solo');
  });
});

describe('UserService.updateProfilePhoto', () => {
  afterEach(() => jest.clearAllMocks());

  test('calls sql.users.update with correct args and returns the URL', async () => {
    sql.users.update.mockResolvedValue([1]);
    const url = await UserService.updateProfilePhoto(1, 'https://cdn.example.com/new.jpg');
    expect(sql.users.update).toHaveBeenCalledWith(
      { profile_photo: 'https://cdn.example.com/new.jpg' },
      { where: { id: 1 } }
    );
    expect(url).toBe('https://cdn.example.com/new.jpg');
  });
});

// ═════════════════════════════════════════════════════════════════════════════
// getProfile controller
// ═════════════════════════════════════════════════════════════════════════════

describe('getProfile controller', () => {
  afterEach(() => jest.clearAllMocks());

  test('returns 403 when token is invalid', async () => {
    getUserInfo.mockResolvedValue(null);
    const req = { headers: { authorization: 'bad' } };
    const res = makeRes();
    await getProfile(req, res);
    expect(res.status).toHaveBeenCalledWith(403);
  });

  test('returns 404 when user not found in DB', async () => {
    getUserInfo.mockResolvedValue({ user_id: 99 });
    sql.users.findOne.mockResolvedValue(null);
    const req = { headers: { authorization: 'token' } };
    const res = makeRes();
    await getProfile(req, res);
    expect(res.status).toHaveBeenCalledWith(404);
  });

  test('returns profile JSON for valid token', async () => {
    getUserInfo.mockResolvedValue({ user_id: 1 });
    sql.users.findOne.mockResolvedValue({
