// ═════════════════════════════════════════════════════════════════════════════

describe('uploadProfilePhoto controller', () => {
  afterEach(() => jest.clearAllMocks());

  test('returns 403 when token is invalid', async () => {
    getUserInfo.mockResolvedValue(null);
    const req = { headers: { authorization: 'bad' }, file: null };
    const res = makeRes();
    await uploadProfilePhoto(req, res);
    expect(res.status).toHaveBeenCalledWith(403);
  });

  test('returns 400 when no file provided', async () => {
    getUserInfo.mockResolvedValue({ user_id: 1 });
    const req = { headers: { authorization: 'token' }, file: null };
    const res = makeRes();
    await uploadProfilePhoto(req, res);
    expect(res.status).toHaveBeenCalledWith(400);
  });

  test('uploads to S3 and returns photoUrl', async () => {
    getUserInfo.mockResolvedValue({ user_id: 7 });
    sql.users.update.mockResolvedValue([1]);
    const req = {
      headers: { authorization: 'token' },
      file: { originalname: 'me.jpg', buffer: Buffer.from('x'), mimetype: 'image/jpeg' },
    };
    const res = makeRes();
    await uploadProfilePhoto(req, res);
    expect(mockPutObject).toHaveBeenCalledWith(expect.objectContaining({
      Key: 'profile-photos/user-7.jpg',
      ACL: 'public-read',
    }));
    expect(res.json).toHaveBeenCalledWith({
      photoUrl: 'https://test-bucket.nyc3.digitaloceanspaces.com/profile-photos/user-7.jpg',
    });
  });
});

