/**
 * Return { firstName, name, email, photoUrl } for the authenticated user.
 * Accepts the decoded JWT ({ user_id, role }). Factory (vendor) users carry a
 * vendor_id in user_id and live in the `vendor` table, not `users`, so we must
 * branch on role — otherwise a vendor's id is looked up in `users`, misses, and
 * the endpoint 404s. Returns null if the user is not found.
 */
UserService.getProfile = async ({ user_id: userId, role }) => {
  if (role === 'vendor') {
    const vendor = await sql.vendor.findOne({
      where: { vendor_id: userId },
      attributes: ['vendor_id', 'vendor_name', 'vendor_lastname', 'vendor_email', 'vendor_profile_photo'],
    });
    if (!vendor) return null;
    return {
      firstName: vendor.vendor_name || '',
      name: `${vendor.vendor_name || ''} ${vendor.vendor_lastname || ''}`.trim(),
      email: vendor.vendor_email || '',
      photoUrl: vendor.vendor_profile_photo || null,
    };
  }
  const user = await sql.users.findOne({
    where: { id: userId },
    attributes: ['id', 'name', 'lastname', 'email', 'profile_photo'],
  });
  if (!user) return null;
  return {
    firstName: user.name || '',
    name: `${user.name || ''} ${user.lastname || ''}`.trim(),
    email: user.email || '',
    photoUrl: user.profile_photo || null,
  };
};

/**
 * Persist a new photo URL for the authenticated user. Returns the URL.
 * Branches on role so vendor avatars land in vendor.vendor_profile_photo
 * instead of writing to a non-existent users row.
 */
UserService.updateProfilePhoto = async ({ user_id: userId, role }, photoUrl) => {
  if (role === 'vendor') {
    await sql.vendor.update(
      { vendor_profile_photo: photoUrl },
      { where: { vendor_id: userId } }
    );
  } else {
    await sql.users.update(
      { profile_photo: photoUrl },
      { where: { id: userId } }
    );
  }
  return photoUrl;
};

