'use strict';
/**
 * Regression tests for the db.js startup migrations.
 *
 * These tests guard against a class of bug where a Sequelize model column is
 * added without a corresponding ALTER TABLE migration.  When that happens,
 * every sql.<model>.findOne() without explicit `attributes` fails because
 * Sequelize generates a SELECT that references the missing column, and
 * PostgreSQL returns "column does not exist".
 *
 * Bug history: profile_photo was added to the users Sequelize model (commit
 * 53cc531) but no ALTER TABLE was included.  Every login attempt (and any
 * other sql.users.findOne() call) failed, producing SYS-030 errors and
 * unhandled-rejection crashes (503 on Cloud Run).
 */

const { readFileSync } = require('fs');
const { join } = require('path');

const DB_JS_PATH        = join(__dirname, '../../models/db.js');
const USERS_MODEL_PATH  = join(__dirname, '../../models/db/users.js');
const RFQITEM_MODEL_PATH = join(__dirname, '../../models/db/RFQItem.js');
const RFQVENDOR_MODEL_PATH = join(__dirname, '../../models/db/RFQVendor.js');
const VENDOR_MODEL_PATH = join(__dirname, '../../models/db/vendor.js');

const dbSource        = readFileSync(DB_JS_PATH,         'utf8');
const usersSource     = readFileSync(USERS_MODEL_PATH,   'utf8');
const rfqItemSource   = readFileSync(RFQITEM_MODEL_PATH, 'utf8');
const rfqVendorSource = readFileSync(RFQVENDOR_MODEL_PATH, 'utf8');
const vendorSource    = readFileSync(VENDOR_MODEL_PATH,  'utf8');

// ─── models/db/users.js ───────────────────────────────────────────────────────

describe('users Sequelize model', () => {
  it('defines profile_photo so Sequelize includes it in generated SELECT queries', () => {
    expect(usersSource).toContain('profile_photo');
  });

  it('defines profile_photo as TEXT type', () => {
    expect(usersSource).toMatch(/profile_photo[\s\S]{0,60}DataTypes\.TEXT/);
  });
});

// ─── models/db.js migrations ─────────────────────────────────────────────────

describe('db.js startup migrations', () => {
  it('contains the profile_photo ALTER TABLE migration', () => {
    // The migration must use ADD COLUMN IF NOT EXISTS so it is safe to re-run.
    expect(dbSource).toMatch(
      /ALTER TABLE.*"users".*ADD COLUMN IF NOT EXISTS\s+profile_photo\s+TEXT/,
    );
  });

  it('profile_photo migration uses IF NOT EXISTS so re-deploys are safe', () => {
    expect(dbSource).toContain('ADD COLUMN IF NOT EXISTS profile_photo TEXT');
  });

  it('existing migrations are still present (rfqItem_duty_rate_equation)', () => {
    expect(dbSource).toContain('rfqItem_duty_rate_equation');
  });

  it('contains the Factory.factory_country migration', () => {
    expect(dbSource).toMatch(
      /ALTER TABLE.*"Factory".*ADD COLUMN IF NOT EXISTS\s+factory_country\s+VARCHAR\(255\)/,
    );
  });

  it('Factory.factory_country backfill exists', () => {
    // Backfill must come from vendor.vendor_country grouped by factory_id_fk.
    expect(dbSource).toMatch(/UPDATE.*"Factory"[\s\S]*vendor_country/i);
  });

  it('existing migrations are still present (customers_logo)', () => {
    expect(dbSource).toContain('customers_logo');
  });

  it('existing migrations are still present (app_settings table)', () => {
    expect(dbSource).toContain('CREATE TABLE IF NOT EXISTS');
    expect(dbSource).toContain('app_settings');
  });

  it('contains the rfqItem_price_sales_snapshots ALTER TABLE migration', () => {
    // ADD COLUMN IF NOT EXISTS so re-deploys are safe.
    expect(dbSource).toMatch(
      /ALTER TABLE.*"RFQItem".*ADD COLUMN IF NOT EXISTS\s+"rfqItem_price_sales_snapshots"\s+TEXT/,
    );
  });

  it('contains the rfqItem_factories_step_at ALTER TABLE migration', () => {
    // Added with the model field so Step changes do not crash RFQItem queries/updates.
    expect(dbSource).toMatch(
      /ALTER TABLE.*"RFQItem".*ADD COLUMN IF NOT EXISTS\s+"rfqItem_factories_step_at"\s+TIMESTAMPTZ/,
    );
  });

  it('quotes the rfqItem_factories_step_at column name in the migration', () => {
    // Sequelize quotes mixed-case identifiers; the migration must create the same column.
    expect(dbSource).not.toMatch(
      /ADD COLUMN IF NOT EXISTS\s+rfqItem_factories_step_at\b/,
    );
  });

  it('quotes the rfqItem_price_sales_snapshots column name in the migration', () => {
    // Sequelize quotes all identifiers, so the model column is created/queried as
    // case-sensitive "rfqItem_price_sales_snapshots". An UNQUOTED ALTER TABLE folds
    // the name to lowercase in Postgres, creating a column Sequelize can never find
    // -> every RFQItem.findAll throws -> RFQ grid breaks with SYS-002. Guard against
    // a regression to the unquoted form.
    expect(dbSource).not.toMatch(
      /ADD COLUMN IF NOT EXISTS\s+rfqItem_price_sales_snapshots\b/,
    );
  });

  it('drops the empty lowercase orphan column left by the bad migration', () => {
    // The original unquoted migration created a lowercase "rfqitem_price_sales_snapshots".
    // It is unused; clean it up. The DROP must target the lowercase orphan specifically.
    expect(dbSource).toMatch(
      /DROP COLUMN IF EXISTS\s+"rfqitem_price_sales_snapshots"/,
    );
  });

  it('never drops the correct mixed-case price_sales_snapshots column', () => {
    // Safety: the cleanup must not touch the real column the feature depends on.
    expect(dbSource).not.toMatch(
      /DROP COLUMN IF EXISTS\s+"rfqItem_price_sales_snapshots"/,
    );
  });

  it('contains the RFQVendor.requote_requested ALTER TABLE migration', () => {
    // ADD COLUMN IF NOT EXISTS, quoted identifier, so re-deploys are safe and the
    // case-sensitive column matches the Sequelize model.
    expect(dbSource).toMatch(
      /ALTER TABLE.*"RFQVendor".*ADD COLUMN IF NOT EXISTS\s+"requote_requested"\s+BOOLEAN/,
    );
  });
});

// ─── models/db/RFQItem.js model ──────────────────────────────────────────────

describe('RFQItem Sequelize model', () => {
  it('defines rfqItem_price_sales_snapshots so Sequelize includes it in generated SELECT queries', () => {
    expect(rfqItemSource).toContain('rfqItem_price_sales_snapshots');
  });

  it('defines rfqItem_price_sales_snapshots as TEXT type', () => {
    expect(rfqItemSource).toMatch(/rfqItem_price_sales_snapshots[\s\S]{0,80}DataTypes\.TEXT/);
  });

  it('defines rfqItem_factories_step_at as DATE type', () => {
    expect(rfqItemSource).toMatch(/rfqItem_factories_step_at[\s\S]{0,80}DataTypes\.DATE/);
  });
});

// ─── models/db/RFQVendor.js model ────────────────────────────────────────────

describe('RFQVendor Sequelize model', () => {
  it('defines requote_requested so Sequelize includes it in generated SELECT queries', () => {
    expect(rfqVendorSource).toContain('requote_requested');
  });

  it('defines requote_requested as BOOLEAN type', () => {
    expect(rfqVendorSource).toMatch(/requote_requested[\s\S]{0,80}DataTypes\.BOOLEAN/);
  });
});

