const Sequelize = require('sequelize');
module.exports = function(sequelize, DataTypes) {
  return sequelize.define('RFQVendor', {
    RFQVendor_id: {
      autoIncrement: true,
      autoIncrementIdentity: true,
      type: DataTypes.INTEGER,
      allowNull: false,
      primaryKey: true
    },
    RFQVendor_amount: {
      type: DataTypes.STRING(255),
      allowNull: true
    },
    RFQVendor_cbm_pc: {
      type: DataTypes.STRING(255),
      allowNull: true
    },
    RFQVendor_status: {
      type: DataTypes.STRING(255),
      allowNull: true
    },
    RFQitem_id_fk: {
      type: DataTypes.INTEGER,
      allowNull: true
    },
    RFQVendor_note: {
      type: DataTypes.STRING,
      allowNull: true
    },
    carton_width: {
      type: DataTypes.DOUBLE,
      allowNull: true
    },
    carton_height: {
      type: DataTypes.DOUBLE,
      allowNull: true
    },
    carton_length: {
      type: DataTypes.DOUBLE,
      allowNull: true
    },
    req_status: {
      type: DataTypes.INTEGER,
      allowNull: true
    },
    vendor_id_fk: {
      type: DataTypes.INTEGER,
      allowNull: true
    },
    quote_date: {
      type: DataTypes.DATEONLY,
      allowNull: true
    },
    std_vendor_id_fk: {
      type: DataTypes.STRING(255),
      allowNull: true
    },
    lead_time: {
      type: DataTypes.INTEGER,
      allowNull: true
    },
    price_terms: {
      type: DataTypes.STRING,
      allowNull: true
    },
    fob_country: {
      type: DataTypes.STRING,
      allowNull: true
    },
    fob_port: {
      type: DataTypes.STRING,
      allowNull: true
    },
    requote_requested: {
      type: DataTypes.BOOLEAN,
      allowNull: true,
      defaultValue: false
    }
  }, {
    sequelize,
    tableName: 'RFQVendor',
    timestamps: false,
    indexes: [
      {
        name: "RFQVendor_pkey",
        unique: true,
        fields: [
          { name: "RFQVendor_id" },
        ]
      },
    ]
  });
};

