Customer.archiveRFQItem = async (req, result) => {
  let data = req.body.data
  data = await utility.mapRFQItem(data)
  const user = await getUserInfo(req.headers.authorization)

  // For vendors, archive is PER-VENDOR — flip their own RFQVendor row, never the
  // global RFQItem.rfqItem_archive flag (which would hide the item from Sourcing and
  // other factories). 'archive' url means the click came from the archive view → restore.
  if (user && user.role === 'vendor') {
    let factoryId = user.factory_id
    if (!factoryId && user.email) {
      const v = await sql.vendor.findOne({ where: { vendor_email: user.email } })
      if (v) factoryId = v.factory_id_fk
    }
    if (!factoryId) return result(null, [0])
    const item = await sql.RFQItem.findOne({
      where: { rfqItem_style_number: data.rfqItem_style_number },
      attributes: ['rfqItem_id']
    })
    if (!item) return result(null, [0])
    return sql.RFQVendor.update(
      { RFQVendor_archived: req.body.url == 'archive' ? false : true },
      { where: { RFQitem_id_fk: item.rfqItem_id, vendor_id_fk: factoryId } }
    )
      .then(d => result(null, d))
      .catch(err => result(err, null))
  }

  // Internal roles keep the global RFQItem archive behavior.
  if (req.body.url == 'archive') {
    data.rfqItem_archive = null
  } else {
    data.rfqItem_archive = 1
  }
  await sql.RFQItem.update(data, {
    where: {
      rfqItem_style_number: data.rfqItem_style_number
    },
    individualHooks: true
  })
    .then(async (data) => {
      if (data) {
        result(null, data);
      }
    })
    .catch(err => {
      result(err, null);
    });
}

