'use strict';

const { Op } = require('sequelize');
const Sequelize = require('sequelize');

/**
 * Per-vendor auto-archive sweep.
 *
 * Archives a single factory's own RFQVendor (quote) rows that:
 *   - have a price provided  (RFQVendor_amount is present, non-empty), and
 *   - were quoted more than `months` months ago (quote_date < CURRENT_DATE - interval), and
 *   - are not already archived.
 *
 * Archiving is recorded on the vendor's own quote row (RFQVendor_archived), NOT on
 * the shared RFQItem, so it is scoped to that factory and never hides the item from
 * Sourcing or from other factories. Idempotent — safe to run on every list load.
 *
 * @param {object} sql        the models/db registry (needs sql.RFQVendor)
 * @param {number} factoryId  the vendor's factory id (RFQVendor.vendor_id_fk holds Factory.id)
 * @param {number} months     age threshold in months (default 3)
 * @returns {Promise<number>} number of rows archived this run
 */
async function archiveStaleVendorQuotes(sql, factoryId, months = 3) {
  if (!factoryId) return 0;

  const [affected] = await sql.RFQVendor.update(
    { RFQVendor_archived: true },
    {
      where: {
        vendor_id_fk: factoryId,
        // Price was actually provided.
        RFQVendor_amount: { [Op.and]: [{ [Op.ne]: null }, { [Op.ne]: '' }] },
        // Quoted, and older than the threshold (compared DB-side so it tracks the
        // server clock and never touches a JS Date — keeps this resume/replay safe).
        quote_date: {
          [Op.ne]: null,
          [Op.lt]: Sequelize.literal(`(CURRENT_DATE - INTERVAL '${Number(months)} months')`),
        },
        // Skip rows already archived so re-runs are cheap and idempotent.
        [Op.or]: [{ RFQVendor_archived: null }, { RFQVendor_archived: false }],
      },
    }
  );

  return affected || 0;
}

module.exports = { archiveStaleVendorQuotes };

